mationMap,        sourceMap, externExports, state.cssNames, state.idGeneratorMap);  }  /**   * Returns an array constructed from errors + temporary warnings.   */  public JSError[] getMessages() {    return getErrors();  }  /**   * Returns the array of errors (never null).   */  public JSError[] getErrors() {    return errorManager.getErrors();  }  /**   * Returns the array of warnings (never null).   */  public JSError[] getWarnings() {    return errorManager.getWarnings();  }  @Override  public Node getRoot() {    return externAndJsRoot;  }  /**   * Creates a new id for making unique names.   */  private int nextUniqueNameId() {    return uniqueNameId++;  }  /**   * Resets the unique name id counter   */  @VisibleForTesting  void resetUniqueNameId() {    uniqueNameId = 0;  }  @Override  Supplier<String> getUniqueNameIdSupplier() {    final Compiler self = this;    return new Supplier<String>() {      @Override      public String get() {        return String.valueOf(self.nextUniqueNameId());      }    };  }  @Override  boolean areNodesEqualForInlining(Node n1, Node n2) {    if (options.ambiguateProperties ||        options.disambiguateProperties) {      // The type based optimizations require that type information is preserved      // during other optimizations.      return n1.isEquivalentToTyped(n2);    } else {      return n1.isEquivalentTo(n2);    }  }  //------------------------------------------------------------------------  // Inputs  //------------------------------------------------------------------------  // TODO(nicksantos): Decide which parts of these belong in an AbstractCompiler  // interface, and which ones should always be injected.  @Override  public CompilerInput getInput(InputId id) {    return inputsById.get(id);  }  /**   * Removes an input file from AST.   * @param id The id of the input to be removed.   */  protected void removeExternInput(InputId id) {    CompilerInput input = getInput(id);    if (input == null) {      return;    }    Preco